package org.eclipse.rdf4j.sail.lmdb.hypergraph;

import java.util.Optional;

/**
 * Facade: run DPhyp with a {@link CostingReceiver} over a {@link PlanHypergraph} and return the best plan covering
 * every node. Empty when the graph is empty or disconnected (no Cartesian products are proposed) or when the pair
 * budget aborted the search.
 */
public final class HypergraphOptimizer {

	private HypergraphOptimizer() {
	}

	public static Optional<JoinPlan> bestPlan(PlanHypergraph planGraph, CostModel costModel) {
		return bestPlan(planGraph, costModel, Long.MAX_VALUE);
	}

	public static Optional<JoinPlan> bestPlan(PlanHypergraph planGraph, CostModel costModel, long pairBudget) {
		if (planGraph.nodeCount() == 0) {
			return Optional.empty();
		}
		CostingReceiver receiver = new CostingReceiver(planGraph, costModel, pairBudget);
		boolean aborted = SubgraphEnumerator.enumerateConnectedPartitions(planGraph.graph(), receiver);
		if (aborted) {
			return Optional.empty();
		}
		return Optional.ofNullable(receiver.planFor(planGraph.graph().allNodes()));
	}
}
